import React from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
} from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { StackNavigationProp } from '@react-navigation/stack';
import { RootStackParamList } from '../types';
import useClaimsStore from '../stores/claimsStore';
import PolicyCard from '../components/PolicyCard';
import ClaimCard from '../components/ClaimCard';

type DashboardScreenNavigationProp = StackNavigationProp<RootStackParamList, 'Dashboard'>;

export default function DashboardScreen() {
  const navigation = useNavigation<DashboardScreenNavigationProp>();
  const profile = useClaimsStore((state) => state.profile);
  const claims = useClaimsStore((state) => state.claims);

  return (
    <View style={styles.container}>
      <ScrollView contentContainerStyle={styles.scroll}>
        <View style={styles.header}>
          <View>
            <Text style={styles.appName}>MotorIQ</Text>
            <Text style={styles.welcomeText}>Welcome back</Text>
          </View>
          <View style={styles.avatar} />
        </View>

        <TouchableOpacity
          style={styles.primaryButton}
          onPress={() => navigation.navigate('ReportAccident')}
        >
          <Text style={styles.primaryButtonText}>Report an Incident</Text>
        </TouchableOpacity>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Active Policy</Text>
          <PolicyCard policy={profile.policy} />
        </View>

        <View style={styles.section}>
          <View style={styles.sectionHeaderRow}>
            <Text style={styles.sectionTitle}>Recent Claims</Text>
            <Text style={styles.linkText}>History</Text>
          </View>
          {claims.slice(0, 3).map((claim) => (
            <ClaimCard
              key={claim.id}
              claim={claim}
              onPress={() => navigation.navigate('ClaimsTracking')}
            />
          ))}
        </View>
      </ScrollView>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F7F9FC',
  },
  scroll: {
    paddingHorizontal: 20,
    paddingTop: 20,
    paddingBottom: 24,
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 24,
  },
  appName: {
    fontSize: 20,
    fontWeight: '700',
    color: '#0B1020',
  },
  welcomeText: {
    fontSize: 14,
    color: '#8F9BB3',
    marginTop: 4,
  },
  avatar: {
    width: 36,
    height: 36,
    borderRadius: 18,
    backgroundColor: '#EDF1F7',
  },
  primaryButton: {
    backgroundColor: '#111827',
    borderRadius: 12,
    paddingVertical: 14,
    alignItems: 'center',
    marginBottom: 24,
  },
  primaryButtonText: {
    color: '#FFFFFF',
    fontSize: 16,
    fontWeight: '600',
  },
  section: {
    marginBottom: 24,
  },
  sectionTitle: {
    fontSize: 16,
    fontWeight: '600',
    color: '#1F2937',
    marginBottom: 12,
  },
  sectionHeaderRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 12,
  },
  linkText: {
    fontSize: 13,
    color: '#4B5563',
  },
  claimCard: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#FFFFFF',
    borderRadius: 12,
    padding: 12,
    marginBottom: 10,
  },
  claimLeft: {
    marginRight: 12,
  },
  claimIcon: {
    width: 40,
    height: 40,
    borderRadius: 12,
    backgroundColor: '#EEF2FF',
  },
  claimMiddle: {
    flex: 1,
  },
  claimTitle: {
    fontSize: 14,
    fontWeight: '600',
    color: '#111827',
  },
  claimSubtitle: {
    fontSize: 12,
    color: '#6B7280',
    marginTop: 2,
  },
  claimStatus: {
    fontSize: 12,
    fontWeight: '600',
    marginTop: 4,
  },
  claimRight: {
    marginLeft: 8,
  },
  claimDate: {
    fontSize: 12,
    color: '#9CA3AF',
  },
});
